# --- Define the interactive plotting function ---
def plot_Tfusion(t1_start=0, t1_end=20, t2_start=200, t2_end=227):
    fig, [ax1, ax2] = plt.subplots(nrows=1, ncols=2, figsize=(18,6),sharex=True)

    ax1.plot(time,data.Temperature, 'gray', alpha=0.3, label='Raw Data')
    ax1.plot(time,temperature, 'black', alpha=0.7, label='Smooth Data')

    # --- First segment ---
    # Use the smooth data for the regression
    seg1 = data[(data.Time >= t1_start) & (data.Time <= t1_end)].copy()
    seg1A = seg1.copy()
    seg1A['Temperature'] = data['Temperature'][(data.Time >= t1_start) & (data.Time <= t1_end)]
    seg1['Temperature'] = temperature[(data.Time >= t1_start) & (data.Time <= t1_end)]
    if len(seg1) >= 2:
        slope1, intercept1, r_value1, p_value1, std_err1 = linregress(seg1.Time, seg1['Temperature'])
        # Extend the line across the full time range
        ax1.plot(data.Time, slope1*data.Time + intercept1, 'r--', label=f'Fit 1: T={slope1:.4f}t+{intercept1:.2f}')

        ax1.plot(seg1.Time, seg1.Temperature, 'r', alpha=0.75,lw=2)
        ax1.plot(seg1A.Time, seg1A.Temperature, 'r', alpha=0.35)


    # --- Second segment ---
    # Use the smooth data for the regression
    seg2 = data[(data.Time >= t2_start) & (data.Time <= t2_end)].copy()
    seg2A = seg2.copy()
    seg2A['Temperature'] = data['Temperature'][(data.Time >= t2_start) & (data.Time <= t2_end)]
    seg2['Temperature'] = temperature[(data.Time >= t2_start) & (data.Time <= t2_end)]

    if len(seg2) >= 2:
        slope2, intercept2, r_value2, p_value2, std_err2 = linregress(seg2.Time, seg2['Temperature'])
        # Extend the line across the full time range
        ax1.plot(data.Time, slope2*data.Time + intercept2, 'b--', label=f'Fit 2: T={slope2:.4f}t+{intercept2:.2f}')
        ax1.plot(seg2.Time, seg2.Temperature, 'b', alpha=0.75,lw=2)
        ax1.plot(seg2A.Time, seg2A.Temperature, 'b', alpha=0.35)

        # --- Cramer's Rule for intersection ---
        D = (-slope1 + slope2)
        if D != 0:
            x_int = (intercept1 - intercept2) / D
            y_int = slope1*x_int + intercept1
            ax1.scatter(x_int, y_int, color='k', s=60, zorder=5, label=(r'T$_{fus}$ = '+f'{y_int:.3f} °C'))

    # Calculate the molar mass
    bB=(y_int-7.01)/-20.459
    mw_pDBrB=0.456/(bB*23.443/1000)


    ax1.set_xlabel('Time (s)')
    ax1.set_ylabel(r'Temperature ($\degree$C)')
    ax1.legend()
    ax1.grid(True)
    ax1.set_ylim(5.0,6.1)

    ax2.plot(diff_time,diff_mix2,'gray',alpha=0.3,label='Raw dT/dt')
    ax2.plot(diff_time,diff_mix2_savgol,'black', alpha=0.7, label='Smoothed dT/dt')

    # Highlight the selected regions in the difference plot
    diff_seg1_indices = (diff_time >= t1_start) & (diff_time <= t1_end)
    ax2.plot(diff_time[diff_seg1_indices], diff_mix2[diff_seg1_indices], 'r', alpha=0.35, lw=2)
    ax2.plot(diff_time[diff_seg1_indices], diff_mix2_savgol[diff_seg1_indices], 'r', alpha=0.75)

    diff_seg2_indices = (diff_time >= t2_start) & (diff_time <= t2_end)
    ax2.plot(diff_time[diff_seg2_indices], diff_mix2[diff_seg2_indices], 'b', alpha=0.35, lw=2)
    ax2.plot(diff_time[diff_seg2_indices], diff_mix2_savgol[diff_seg2_indices], 'b', alpha=0.75)
    ax2.set_xlabel('Time (s)')
    ax2.set_ylabel('dT/dt')
    ax2.grid(True)
    ax2
    ax2.text(100,-0.0175,f"Calculated Molar Mass: {mw_pDBrB:.3f} g/mol",fontsize=12)
    ax2.text(100,-0.0195,f"Actual Molar Mass: 235.906 g/mol",fontsize=12)
    ax2.legend()
    plt.show()

# --- Create four sliders in seconds ---
interact(
    plot_Tfusion,
    t1_start=widgets.FloatSlider(value=0, min=0, max=227, step=0.2, description='t1 (s)'),
    t1_end=widgets.FloatSlider(value=20, min=0, max=227, step=0.2, description='t2 (s)'),
    t2_start=widgets.FloatSlider(value=200, min=0, max=227, step=0.2, description='t3 (s)'),
    t2_end=widgets.FloatSlider(value=227, min=0, max=227, step=0.2, description='t4 (s)')
);

